const rows = $input.all().map(i => i.json);
const candidates = rows.map(r => ({
  id:               r['Auto-ID'],
  name:             r['Applicant Name'],
  role:             ((r['Position Level'] || '') + ' ' + (r['Position Type'] || '')).trim(),
  source:           r['Channel'],
  stage:            r['Offered'] === 'Yes' ? 'Offer' : (r['Rejected'] === 'Yes' ? 'Rejected' : 'Interview'),
  days_in_pipeline: parseInt(r['Rounds Completed'] || 0) * 7,
  rejection_reason: r['Rejected Reason'] || null,
  offer_declined:   r['Offer Acceptance'] === 'No',
  reschedules:      parseInt(r['Re-Schedules'] || 0),
  round_score:      parseFloat(r['Cumulative Round Score'] || 0),
  position_id:      r['Position-ID'],
  interviewers:     (r['Interviewers'] || '').split(';').map(s => s.trim()).filter(Boolean)
}));
const interviewerMap = {};
for (const c of candidates) {
  for (const iv of c.interviewers) {
    if (!iv) continue;
    interviewerMap[iv] = (interviewerMap[iv] || 0) + 1;
  }
}
const interviewers = Object.entries(interviewerMap).map(([name, panels_this_month]) => ({ name, panels_this_month, capacity: 10 }));
const roleMap = {};
for (const c of candidates) {
  if (!roleMap[c.role]) roleMap[c.role] = { role: c.role, days_open: 0 };
  roleMap[c.role].days_open = Math.max(roleMap[c.role].days_open, c.days_in_pipeline);
}
const open_roles = Object.values(roleMap).map(r => ({
  role: r.role,
  days_open: r.days_open,
  sla_days: (r.role.toLowerCase().includes('staff') || r.role.toLowerCase().includes('principal')) ? 45 : 30
}));
return [{ json: { run_id: 'run_' + Date.now(), timestamp: new Date().toISOString(), candidates, interviewers, open_roles } }];

const data = $input.first().json;
const routing = {
  sourcing_quality:    { model: 'gpt-4o-mini', reason: 'Pattern matching over sources' },
  rejection_pattern:   { model: 'gpt-4o',      reason: 'Nuanced root-cause analysis' },
  panel_load_balancer: { model: 'gpt-4o-mini', reason: 'Simple numeric comparison' },
  offer_insights:      { model: 'gpt-4o',      reason: 'Multi-factor decline reasoning' },
  pipeline_health:     { model: 'gpt-4o-mini', reason: 'SLA and funnel math' }
};
return [{ json: { ...data, routing } }];

// Aggregate all 5 agent outputs into one structured result
// Inputs: 5 items from Output Capture nodes (Sourcing, Rejection,
// Panel, Offer, Pipeline)

const insights = $input.all().map(i => i.json);

if (insights.length === 0) {
  throw new Error('No agent outputs received — check connections');
}

// ── Cost aggregation ──────────────────────────────────────────
let total_prompt_tokens     = 0;
let total_completion_tokens = 0;
let total_tokens            = 0;
let total_estimated_usd     = 0;
let total_llm_calls         = 0;
let rag_used_count          = 0;

for (const ins of insights) {
  total_prompt_tokens     += (ins.prompt_tokens     || 0);
  total_completion_tokens += (ins.completion_tokens || 0);
  total_tokens            += (ins.total_tokens      || 0);
  total_estimated_usd     += (ins.estimated_usd     || 0);
  total_llm_calls         += (ins.llm_calls         || 0);
  if (ins.rag_used) rag_used_count++;
}
total_estimated_usd = parseFloat(total_estimated_usd.toFixed(6));

// ── Latency stats ─────────────────────────────────────────────
const latencies = insights
  .map(i => i.latency_ms)
  .filter(l => typeof l === 'number');

const avg_latency_ms = latencies.length
  ? Math.round(latencies.reduce((a, b) => a + b, 0) / latencies.length)
  : null;
const max_latency_ms = latencies.length ? Math.max(...latencies) : null;
const min_latency_ms = latencies.length ? Math.min(...latencies) : null;

// p95 latency
const sortedLat = [...latencies].sort((a, b) => a - b);
const p95_idx = Math.ceil(0.95 * sortedLat.length) - 1;
const p95_latency_ms = sortedLat.length ? sortedLat[Math.max(0, p95_idx)] : null;

// Slowest / most expensive
const slowest = insights.reduce((s, i) =>
  (i.latency_ms || 0) > (s.latency_ms || 0) ? i : s, insights[0]);
const most_expensive = insights.reduce((m, i) =>
  (i.estimated_usd || 0) > (m.estimated_usd || 0) ? i : m, insights[0]);

// Per-agent cost summary (for the dashboard)
const cost_by_agent = insights.map(i => ({
  agent:              i.agent,
  model:              i.cost_of_insight?.model,
  prompt_tokens:      i.prompt_tokens     || 0,
  completion_tokens:  i.completion_tokens || 0,
  total_tokens:       i.total_tokens      || 0,
  estimated_usd:      i.estimated_usd     || 0,
  latency_ms:         i.latency_ms        || null,
  llm_calls:          i.llm_calls         || 0,
  rag_used:           !!i.rag_used,
}));

return [{ json: {
  insights,
  cost_aggregate: {
    total_prompt_tokens,
    total_completion_tokens,
    total_tokens,
    total_estimated_usd,
    total_llm_calls,
    rag_used_count,
    rag_usage_rate: parseFloat((rag_used_count / insights.length).toFixed(2)),
    avg_latency_ms,
    max_latency_ms,
    min_latency_ms,
    p95_latency_ms,
    slowest_agent:        slowest.agent,
    most_expensive_agent: most_expensive.agent,
    cost_by_agent,
  }
} }];

// Cost & Optimization Agent — uses real aggregated totals
const { insights, cost_aggregate, evaluation_summary } = $input.first().json;

// ── Total cost (insights + evaluation) ────────────────────────────
const insights_usd    = cost_aggregate.total_estimated_usd;
const insights_tokens = cost_aggregate.total_tokens;
const eval_usd        = evaluation_summary.eval_cost?.estimated_usd     || 0;
const eval_tokens     = evaluation_summary.eval_cost?.total_tokens      || 0;

const grand_total_usd    = parseFloat((insights_usd    + eval_usd).toFixed(6));
const grand_total_tokens = insights_tokens + eval_tokens;

// ── Optimization recommendations ──────────────────────────────────
const suggestions = [];

// (1) Find gpt-4o agents that scored well on eval — candidates for downgrade
for (const ins of insights) {
  const model = ins.cost_of_insight?.model;
  const evalScore = ins.evaluation?.combined_score || 0;
  const cost = ins.estimated_usd || 0;

  if (model === 'gpt-4o' && evalScore >= 0.85 && cost > 0.001) {
    const expected_after = parseFloat((cost * 0.3).toFixed(6));
    suggestions.push({
      type:           'downgrade',
      agent:          ins.agent,
      current_model:  model,
      recommended:    'gpt-4o-mini',
      eval_score:     evalScore,
      current_cost:   cost,
      expected_cost:  expected_after,
      estimated_saving_usd: parseFloat((cost - expected_after).toFixed(6)),
      rationale:      'High eval score (' + evalScore + ') suggests structured task — mini may suffice.',
    });
  }

  // (2) Flag gpt-4o-mini agents with low eval scores — candidates for upgrade
  if (model === 'gpt-4o-mini' && evalScore < 0.6) {
    suggestions.push({
      type:           'upgrade',
      agent:          ins.agent,
      current_model:  model,
      recommended:    'gpt-4o',
      eval_score:     evalScore,
      current_cost:   cost,
      expected_cost:  parseFloat((cost * 16).toFixed(6)),
      estimated_extra_usd: parseFloat((cost * 15).toFixed(6)),
      rationale:      'Low eval score (' + evalScore + ') — gpt-4o may produce better insight.',
    });
  }

  // (3) Flag missing RAG usage
  if (!ins.rag_used) {
    suggestions.push({
      type:           'rag_grounding',
      agent:          ins.agent,
      rationale:      'Agent did not call its RAG tool. Tighten tool description or system message to force grounding.',
    });
  }
}

// (4) Flag high latency
if (cost_aggregate.max_latency_ms > 8000) {
  suggestions.push({
    type:        'latency',
    agent:       cost_aggregate.slowest_agent,
    rationale:   'Latency ' + cost_aggregate.max_latency_ms + 'ms exceeds 8s threshold. Consider prompt compression or lighter model.',
  });
}

if (!suggestions.length) {
  suggestions.push({
    type: 'all_optimal',
    rationale: 'All agents within cost, latency, and quality targets.',
  });
}

// Total potential saving from all downgrade suggestions
const potential_saving_usd = suggestions
  .filter(s => s.type === 'downgrade')
  .reduce((s, x) => s + (x.estimated_saving_usd || 0), 0);

return [{ json: {
  insights,
  cost_aggregate,
  evaluation_summary,
  cost_optimization: {
    grand_total_usd,
    grand_total_tokens,
    insights_usd,
    eval_usd,
    insights_tokens,
    eval_tokens,
    potential_saving_usd: parseFloat(potential_saving_usd.toFixed(6)),
    suggestions,
  }
} }];

const { insights, cost_aggregate, evaluation_summary, cost_optimization } = $input.first().json;
const { candidates, interviewers } = $node['Routing Agent'].json;

// Pipeline stats from candidate data
const total       = candidates.length;
const offered     = candidates.filter(c => c.stage === 'Offer').length;
const accepted    = candidates.filter(c => c.stage === 'Offer' && !c.offer_declined).length;
const rejected    = candidates.filter(c => c.stage === 'Rejected').length;
const active      = total - offered - rejected;
const completed   = candidates.filter(c => c.stage !== 'Interview').length;

const pct = (n, d) => d ? parseFloat((n / d * 100).toFixed(1)) : 0;

const channelMap = {};
for (const c of candidates) {
  const ch = c.source || 'Unknown';
  if (!channelMap[ch]) channelMap[ch] = { total:0, offers:0, accepted:0 };
  channelMap[ch].total++;
  if (c.stage === 'Offer') channelMap[ch].offers++;
  if (c.stage === 'Offer' && !c.offer_declined) channelMap[ch].accepted++;
}
const channel_stats = Object.entries(channelMap).map(([channel, s]) => ({
  channel, total: s.total, offers: s.offers, accepted: s.accepted,
  offer_rate:  pct(s.offers,   s.total),
  accept_rate: pct(s.accepted, s.offers),
}));

const rejReasonMap = {};
for (const c of candidates.filter(c => c.stage === 'Rejected')) {
  const r = c.rejection_reason || 'Unknown';
  rejReasonMap[r] = (rejReasonMap[r] || 0) + 1;
}
const rejection_reasons = Object.entries(rejReasonMap)
  .map(([reason, count]) => ({ reason, count }))
  .sort((a,b) => b.count - a.count);

const reschedMap = {};
for (const c of candidates) {
  const r = String(c.reschedules || 0);
  reschedMap[r] = (reschedMap[r] || 0) + 1;
}
const reschedule_dist = Object.entries(reschedMap)
  .map(([reschedules, count]) => ({ reschedules, count }))
  .sort((a,b) => parseInt(a.reschedules) - parseInt(b.reschedules));

const avg_load = interviewers.length
  ? parseFloat((interviewers.reduce((s,i) => s + i.panels_this_month, 0) / interviewers.length).toFixed(1))
  : 0;
const interviewer_stats = interviewers
  .map(i => ({
    ...i,
    status: i.panels_this_month > 65 ? 'Overloaded'
           : i.panels_this_month > avg_load * 1.1 ? 'At limit'
           : i.panels_this_month < avg_load * 0.95 ? 'Available' : 'Healthy'
  }))
  .sort((a,b) => b.panels_this_month - a.panels_this_month);

return [{ json: {
  status: 'complete',
  generated_at: new Date().toISOString(),

  run_summary: {
    agents_run:             insights.length,
    total_cost_usd:         cost_optimization.grand_total_usd,
    insights_cost_usd:      cost_optimization.insights_usd,
    eval_cost_usd:          cost_optimization.eval_usd,
    total_tokens:           cost_optimization.grand_total_tokens,
    prompt_tokens:          cost_aggregate.total_prompt_tokens,
    completion_tokens:      cost_aggregate.total_completion_tokens,
    avg_latency_ms:         cost_aggregate.avg_latency_ms,
    max_latency_ms:         cost_aggregate.max_latency_ms,
    p95_latency_ms:         cost_aggregate.p95_latency_ms,
    slowest_agent:          cost_aggregate.slowest_agent,
    most_expensive_agent:   cost_aggregate.most_expensive_agent,
    rag_usage_rate:         cost_aggregate.rag_usage_rate,
    eval_method:            evaluation_summary.method,
    eval_pass_rate:         evaluation_summary.pass_rate,
    eval_avg_score:         evaluation_summary.avg_combined_score,
    potential_saving_usd:   cost_optimization.potential_saving_usd,
  },

  pipeline_stats: {
    total, offered, accepted, rejected, active, completed,
    offer_rate:  pct(offered,  total),
    accept_rate: pct(accepted, offered),
    reject_rate: pct(rejected, total),
    active_rate: pct(active,   total),
  },
  channel_stats,
  rejection_reasons,
  reschedule_dist,
  interviewer_stats,
  avg_interviewer_load: avg_load,

  insights,
  cost_aggregate,
  evaluation_summary,
  cost_optimization,
} }];

// Get File SHA runs first and passes its result here
const shaResponse = $input.first().json;
// sha is present if file already exists; undefined on first run (404)
const sha = shaResponse?.sha || undefined;

// Read Final Output data from previous node reference
const output = $node['Final Output'].json;
const jsonString = JSON.stringify(output, null, 2);
const encoded = Buffer.from(jsonString, 'utf8').toString('base64');

return [{ json: {
  content: encoded,
  message: 'n8n run — ' + new Date().toISOString(),
  sha,
} }];

// Build the user message for the Sourcing Quality Agent
const { candidates } = $node['Routing Agent'].json;

// Compute source statistics live from candidate data
const sourceCounts = {};
const sourceAccepted = {};
for (const c of candidates) {
  const ch = c.source || 'Unknown';
  sourceCounts[ch] = (sourceCounts[ch] || 0) + 1;
  if (c.stage === 'Offer' && !c.offer_declined) {
    sourceAccepted[ch] = (sourceAccepted[ch] || 0) + 1;
  }
}

// Capture start time for latency tracking
const start_time = Date.now();

// Compose the user prompt — the Agent decides if/when to fetch RAG context
const userMessage = [
  'You are the Sourcing Quality Agent. Analyse the hiring sourcing data below.',
  '',
  'CURRENT DATA:',
  'Source channel counts: ' + JSON.stringify(sourceCounts),
  'Accepted offers by source: ' + JSON.stringify(sourceAccepted),
  '',
  'Use the knowledge base tool to retrieve relevant sourcing benchmarks before answering.',
  'Then return ONLY a JSON object in this exact shape:',
  '{',
  '  "recommendation": "<one clear actionable sentence>",',
  '  "evidence": { "source_counts": {}, "accepted_by_source": {}, "key_insight": "<string>" },',
  '  "confidence_score": 0.0,',
  '  "cost_of_insight": { "model": "gpt-4o-mini", "estimated_tokens": 0, "estimated_usd": 0.0 },',
  '  "alternative": { "model": "gpt-4o", "trade_off": "<string>" }',
  '}'
].join('\n');

return [{ json: {
  agent:          'sourcing_quality',
  userMessage,
  start_time,
  source_counts:  sourceCounts,
  source_accepted: sourceAccepted,
} }];

// ── Robust token extraction for n8n AI Agent (workaround) ──────────
// n8n's Agent node does NOT expose tokenUsage in its main output
// (GitHub issue #26302). We use a deterministic estimation approach:
//   - Estimate input tokens from user message + system message + RAG context
//   - Estimate output tokens from agent's JSON response
//   - ~4 chars per token (English), ~3 chars per token (JSON/code)
//   - Multiplied by observed llm_calls (planning + final, typically 2)

const agentOut = $input.first().json;
const prepData = $node['Sourcing Data Prep'].json;

// ── Latency ──────────────────────────────────────────────────
const latency_ms = prepData.start_time ? (Date.now() - prepData.start_time) : null;

// ── Token estimation helper ──────────────────────────────────
// Conservative: 3.5 chars/token (between 3 for JSON and 4 for prose)
const estimateTokens = (str) => Math.ceil((str || '').length / 3.5);

// ── Detect RAG tool usage and extract context ─────────────────
const steps = agentOut.intermediateSteps || [];
const ragUsed = steps.some(s => (s.action?.tool || '').includes('sourcing'));
const ragContext = steps
  .filter(s => (s.action?.tool || '').includes('sourcing'))
  .map(s => s.observation || '')
  .join('\n\n');

// ── Count LLM calls ──────────────────────────────────────────
// Each step in intermediateSteps = one tool call, plus the final answer LLM call
const llm_calls = steps.length + 1;

// ── Estimate input tokens ────────────────────────────────────
// User message (sent to model on every call)
// + RAG context (sent again to model after tool call)
// + minimal system message overhead (~150 tokens)
const userMsgTokens   = estimateTokens(prepData.userMessage || '');
const ragContextTokens = estimateTokens(ragContext);
const systemOverhead   = 150;

// Each LLM call sends the running conversation. Approximation:
//   Call 1 (planning):  system + user_msg                       
//   Call 2 (final):     system + user_msg + tool_call + ragContext
const prompt_tokens = (userMsgTokens + systemOverhead) * llm_calls
                    + ragContextTokens;

// ── Estimate output tokens ───────────────────────────────────
// Output = the JSON response. Tool call outputs are short (~30 tokens).
const outputText = agentOut.output || '';
const completion_tokens = estimateTokens(outputText) + (steps.length * 30);

const total_tokens = prompt_tokens + completion_tokens;

// ── Cost calculation ─────────────────────────────────────────
const INPUT_RATE  = 0.00015;
const OUTPUT_RATE = 0.0006;
const estimated_usd = parseFloat(
  ((prompt_tokens / 1000 * INPUT_RATE) + (completion_tokens / 1000 * OUTPUT_RATE)).toFixed(6)
);

// ── Parse the Agent's JSON output ────────────────────────────
const raw = (agentOut.output || '').replace(/```json|```/g, '').trim();
let parsed;
try { parsed = JSON.parse(raw); }
catch (e) { parsed = { recommendation: raw, parse_error: e.message }; }

// ── Overwrite cost_of_insight with measured values ───────────
parsed.cost_of_insight = {
  model:              'gpt-4o-mini',
  prompt_tokens,
  completion_tokens,
  total_tokens,
  estimated_usd,
  llm_calls,
  estimation_method:  'deterministic_char_count',
  input_rate_per_1k:  INPUT_RATE,
  output_rate_per_1k: OUTPUT_RATE,
};

return [{ json: {
  agent:          'sourcing_quality',
  ...parsed,
  rag_context:    ragContext,
  rag_used:       ragUsed,
  latency_ms,
  prompt_tokens,
  completion_tokens,
  total_tokens,
  estimated_usd,
  llm_calls,
  run_timestamp:  new Date().toISOString(),
} }];

// Build the user message for the Rejection Pattern Agent
const { candidates } = $node['Routing Agent'].json;
const rejected = candidates.filter(c => c.stage === 'Rejected');
const reasons = {};
for (const c of rejected) {
  const r = c.rejection_reason || 'Unknown';
  reasons[r] = (reasons[r] || 0) + 1;
}

// Capture start time for latency tracking
const start_time = Date.now();

// Compose the user prompt
const userMessage = [
  'You are the Rejection Pattern Agent. Analyse the data below.',
  '',
  'CURRENT DATA:',
  'Total rejections: ' + rejected.length,
  'Rejection reasons breakdown: ' + JSON.stringify(reasons),
  '',
  'Use the rejection_benchmarks tool to retrieve relevant benchmarks before answering.',
  'Then return ONLY a JSON object in this exact shape:',
  '{',
  '  "recommendation": "<one clear actionable sentence>",',
  '  "evidence": { "total_rejections": 0, "reasons_breakdown": {}, "key_insight": "<string>" },',
  '  "confidence_score": 0.0,',
  '  "cost_of_insight": { "model": "gpt-4o", "estimated_tokens": 0, "estimated_usd": 0.0 },',
  '  "alternative": { "model": "<other>", "trade_off": "<string>" }',
  '}'
].join('\n');

return [{ json: {
  agent:          'rejection_pattern',
  userMessage,
  start_time, rejected_count: rejected.length, reasons,
} }];

// ── Robust token extraction for n8n AI Agent (workaround) ──────────
// n8n's Agent node does NOT expose tokenUsage in its main output
// (GitHub issue #26302). We use a deterministic estimation approach:
//   - Estimate input tokens from user message + system message + RAG context
//   - Estimate output tokens from agent's JSON response
//   - ~4 chars per token (English), ~3 chars per token (JSON/code)
//   - Multiplied by observed llm_calls (planning + final, typically 2)

const agentOut = $input.first().json;
const prepData = $node['Rejection Pattern Data Prep'].json;

// ── Latency ──────────────────────────────────────────────────
const latency_ms = prepData.start_time ? (Date.now() - prepData.start_time) : null;

// ── Token estimation helper ──────────────────────────────────
// Conservative: 3.5 chars/token (between 3 for JSON and 4 for prose)
const estimateTokens = (str) => Math.ceil((str || '').length / 3.5);

// ── Detect RAG tool usage and extract context ─────────────────
const steps = agentOut.intermediateSteps || [];
const ragUsed = steps.some(s => (s.action?.tool || '').includes('rejection'));
const ragContext = steps
  .filter(s => (s.action?.tool || '').includes('rejection'))
  .map(s => s.observation || '')
  .join('\n\n');

// ── Count LLM calls ──────────────────────────────────────────
// Each step in intermediateSteps = one tool call, plus the final answer LLM call
const llm_calls = steps.length + 1;

// ── Estimate input tokens ────────────────────────────────────
// User message (sent to model on every call)
// + RAG context (sent again to model after tool call)
// + minimal system message overhead (~150 tokens)
const userMsgTokens   = estimateTokens(prepData.userMessage || '');
const ragContextTokens = estimateTokens(ragContext);
const systemOverhead   = 150;

// Each LLM call sends the running conversation. Approximation:
//   Call 1 (planning):  system + user_msg                       
//   Call 2 (final):     system + user_msg + tool_call + ragContext
const prompt_tokens = (userMsgTokens + systemOverhead) * llm_calls
                    + ragContextTokens;

// ── Estimate output tokens ───────────────────────────────────
// Output = the JSON response. Tool call outputs are short (~30 tokens).
const outputText = agentOut.output || '';
const completion_tokens = estimateTokens(outputText) + (steps.length * 30);

const total_tokens = prompt_tokens + completion_tokens;

// ── Cost calculation ─────────────────────────────────────────
const INPUT_RATE  = 0.0025;
const OUTPUT_RATE = 0.01;
const estimated_usd = parseFloat(
  ((prompt_tokens / 1000 * INPUT_RATE) + (completion_tokens / 1000 * OUTPUT_RATE)).toFixed(6)
);

// ── Parse the Agent's JSON output ────────────────────────────
const raw = (agentOut.output || '').replace(/```json|```/g, '').trim();
let parsed;
try { parsed = JSON.parse(raw); }
catch (e) { parsed = { recommendation: raw, parse_error: e.message }; }

// ── Overwrite cost_of_insight with measured values ───────────
parsed.cost_of_insight = {
  model:              'gpt-4o',
  prompt_tokens,
  completion_tokens,
  total_tokens,
  estimated_usd,
  llm_calls,
  estimation_method:  'deterministic_char_count',
  input_rate_per_1k:  INPUT_RATE,
  output_rate_per_1k: OUTPUT_RATE,
};

return [{ json: {
  agent:          'rejection_pattern',
  ...parsed,
  rag_context:    ragContext,
  rag_used:       ragUsed,
  latency_ms,
  prompt_tokens,
  completion_tokens,
  total_tokens,
  estimated_usd,
  llm_calls,
  run_timestamp:  new Date().toISOString(),
} }];

// Build the user message for the Panel Load Balancer Agent
const { interviewers } = $node['Routing Agent'].json;

// Capture start time for latency tracking
const start_time = Date.now();

// Compose the user prompt
const userMessage = [
  'You are the Panel Load Balancer Agent. Analyse the data below.',
  '',
  'CURRENT DATA:',
  'Interviewer panel loads: ' + JSON.stringify(interviewers),
  '',
  'Use the panel_benchmarks tool to retrieve relevant benchmarks before answering.',
  'Then return ONLY a JSON object in this exact shape:',
  '{',
  '  "recommendation": "<one clear actionable sentence>",',
  '  "evidence": { "overloaded": [], "underloaded": [], "key_insight": "<string>" },',
